const SESSION_TTL_MS=3e5,SESSION_BYTE_LIMIT=125829120,uploadSessions=new Map;let sweepCursor=0;function nowMs(){return Date.now()}function cleanMimeType(e){return String(e||"").trim()||"image/png"}function shouldKeepUntilManualRelease(e){return!0===e?.meta?.retainUntilRelease}function debugSessionPrune(e,n){try{!0===globalThis.__XiaoLiangRH_SESSION_DEBUG__&&console.warn("[XiaoLiangRH upload session expired]",e,n?.meta||{})}catch{}}function sweepExpiredSessions(){const e=nowMs();sweepCursor+=1;for(const[n,o]of uploadSessions.entries())shouldKeepUntilManualRelease(o)||e-o.createdAt>=3e5&&(debugSessionPrune(n,o),uploadSessions.delete(n))}function assertBytes(e){if(!(e instanceof Uint8Array)||e.length<=0)throw new Error("[XiaoLiangRH] upload session: empty bytes");if(e.length>125829120)throw new Error("[XiaoLiangRH] upload session: too large")}function createSessionId(){const e=Math.random().toString(36).slice(2,10);return`xlrh_upload_${nowMs().toString(36)}_${sweepCursor.toString(36)}_${e}`}function publicRecord(e){return e?{bytes:e.bytes,mimeType:e.mimeType,meta:e.meta||{}}:null}function readRecord(e){const n=String(e||"").trim();return n?(sweepExpiredSessions(),uploadSessions.get(n)||null):null}export function putUploadSession(e,n,o={}){sweepExpiredSessions(),assertBytes(e);const s=createSessionId();return uploadSessions.set(s,{bytes:e,mimeType:cleanMimeType(n),meta:o&&"object"==typeof o?{...o}:{},createdAt:nowMs()}),s}export function takeUploadSession(e){const n=readRecord(e);return n?(uploadSessions.delete(String(e||"").trim()),publicRecord(n)):null}export function peekUploadSession(e){return publicRecord(readRecord(e))}export function releaseUploadSession(e){const n=String(e||"").trim();n&&uploadSessions.delete(n)}